#2025-03-25 创建多关节
import pybullet as p
import time
import pybullet_data

p.connect(p.GUI)
p.setAdditionalSearchPath(pybullet_data.getDataPath())
colPlaneId = p.createCollisionShape(p.GEOM_PLANE)
sphereUid = p.createMultiBody(0, 0)
print(f"sphereUid_createMultiBody is {sphereUid}")
print(f"colPlaneId is {colPlaneId}")
sphereRadius = 0.05
colSphereId = p.createCollisionShape(p.GEOM_SPHERE, radius=sphereRadius)
print(f"colSphereID is{colSphereId}")
colBoxId = p.createCollisionShape(p.GEOM_BOX,
                                  halfExtents=[sphereRadius, sphereRadius, sphereRadius])
print(f"colBoxId is{colBoxId}")
mass = 1
visualShapeId = -1

link_Masses = [1]
linkCollisionShapeIndices = [colBoxId]
linkVisualShapeIndices = [-1]
linkPositions = [[0, 0, 0.15]]
linkOrientations = [[0, 0, 0, 1]]
linkInertialFramePositions = [[0, 0, 0]]
linkInertialFrameOrientations = [[0, 0, 0, 1]]
indices = [0]
jointTypes = [p.JOINT_REVOLUTE]
axis = [[0, 0, 1]]

# for i in range(5):  # 增加关节数量
#     link_Masses.append(1)
#     linkPositions.append([0, 0, 0.11 * (i + 1)])
#     jointTypes.append(p.JOINT_REVOLUTE)
#     axis.append([0, 0, 1])

for i in range(3): # 增加关节数量
  for j in range(3):
    for k in range(3):
      basePosition = [
          1 + i * 5 * sphereRadius, 1 + j * 5 * sphereRadius, 1 + k * 5 * sphereRadius + 1
      ]
      baseOrientation = [0, 0, 0, 1]
      if (k & 2):
        sphereUid = p.createMultiBody(mass, colSphereId, visualShapeId, basePosition,
                                      baseOrientation)
        print(f"ball shpereUid {sphereUid} and the basePosition is {basePosition}")
      else:
        sphereUid = p.createMultiBody(mass,
                                      colBoxId, # colSphereId,  
                                      visualShapeId,
                                      basePosition,
                                      baseOrientation,
                                      linkMasses=link_Masses,
                                      linkCollisionShapeIndices=linkCollisionShapeIndices,
                                      linkVisualShapeIndices=linkVisualShapeIndices,
                                      linkPositions=linkPositions,
                                      linkOrientations=linkOrientations,
                                      linkInertialFramePositions=linkInertialFramePositions,
                                      linkInertialFrameOrientations=linkInertialFrameOrientations,
                                      linkParentIndices=indices,
                                      linkJointTypes=jointTypes,
                                      linkJointAxis=axis)
        print(f"box shpereUid {sphereUid} and the basePosition is {basePosition}")

      p.changeDynamics(sphereUid,
                       -1,
                       spinningFriction=0.1,
                       rollingFriction=0.1,
                       linearDamping=0.0)
      print(f"number of joints of the current shpereUid #{sphereUid} is {p.getNumJoints(sphereUid)}")
      
      for joint in range(p.getNumJoints(sphereUid)):
        p.setJointMotorControl2(sphereUid, joint, p.VELOCITY_CONTROL, targetVelocity=1, force=10)
      for i in range(p.getNumJoints(sphereUid)):
        # Ref: https://zhuanlan.zhihu.com/p/590190456
        # 打印关节信息
        print(p.getJointInfo(sphereUid, i)[1].decode('UTF-8'))

p.setGravity(0, 0, -10)
p.setRealTimeSimulation(1)

p.getNumJoints(sphereUid)
for i in range(p.getNumJoints(sphereUid)):
  print(p.getJointInfo(sphereUid, i)[0])

velocitySlider = p.addUserDebugParameter("Velocity", 0, 5, 1)

while (1):
  # keys = p.getKeyboardEvents()
  # print(keys)    
  targetVelocity = p.readUserDebugParameter(velocitySlider)
  sphereUid = 1
  joint = 0
  p.setJointMotorControl2( 1, 0, p.VELOCITY_CONTROL, 
                          targetVelocity=targetVelocity, force=10)

  time.sleep(0.01)